class Player {
  String name = 'Unknown';
  int score = 0;
}

void main() {
  Player p1 = Player();
  p1.name = 'Mario';
  p1.score = 500;

  Player p2 = Player();
  p2.name = 'Luigi';

  print(p1.name); // Mario
  print(p2.name); // Luigi
}
